export declare const widgetStyles = "\n:host {\n  all: initial;\n  color-scheme: light;\n  --a11y-primary: #1f4fd6;\n  --a11y-bg: #ffffff;\n  --a11y-bg-soft: #f8fafc;\n  --a11y-text: #0f172a;\n  --a11y-text-muted: #64748b;\n  --a11y-border: #dbe3ee;\n  --a11y-focus: #f59e0b;\n  --a11y-shadow: 0 10px 30px rgba(15, 23, 42, 0.12);\n}\n\n*, *::before, *::after {\n  box-sizing: border-box;\n}\n\n.a11y-shell {\n  position: fixed;\n  right: 20px;\n  bottom: 20px;\n  z-index: var(--a11y-z-index, 2147483000);\n  display: flex;\n  flex-direction: column;\n  align-items: flex-end;\n  gap: 12px;\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n  color: var(--a11y-text);\n}\n\n.a11y-shell[data-position=\"bottom-left\"] {\n  left: 20px;\n  right: auto;\n  align-items: flex-start;\n}\n\n.a11y-fab {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  gap: 10px;\n  min-width: 48px;\n  height: 48px;\n  padding: 0 16px;\n  border: 1px solid rgba(255, 255, 255, 0.18);\n  border-radius: 999px;\n  background: var(--a11y-primary);\n  color: #ffffff;\n  box-shadow: 0 8px 22px rgba(31, 41, 55, 0.18);\n  cursor: pointer;\n  font: 600 14px/1 system-ui, sans-serif;\n  transition: transform 160ms ease, background-color 160ms ease, box-shadow 160ms ease;\n}\n\n.a11y-fab:hover {\n  transform: scale(1.02);\n}\n\n.a11y-fab:active {\n  transform: scale(0.98);\n}\n\n.a11y-fab:focus-visible,\n.a11y-panel button:focus-visible,\n.a11y-panel input:focus-visible,\n.a11y-panel select:focus-visible {\n  outline: 3px solid var(--a11y-focus);\n  outline-offset: 2px;\n}\n\n.a11y-fab-icon,\n.a11y-close-icon {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.a11y-panel {\n  width: min(368px, calc(100vw - 32px));\n  max-height: min(78vh, 640px);\n  border: 1px solid var(--a11y-border);\n  border-radius: 20px;\n  background: var(--a11y-bg);\n  box-shadow: var(--a11y-shadow);\n  overflow: hidden;\n  display: grid;\n  grid-template-rows: auto minmax(0, 1fr) auto;\n  opacity: 0;\n  transform: translateY(10px);\n  pointer-events: none;\n  visibility: hidden;\n  transition: opacity 180ms ease, transform 180ms ease, visibility 180ms ease;\n}\n\n.a11y-panel[data-open=\"true\"] {\n  opacity: 1;\n  transform: translateY(0);\n  pointer-events: auto;\n  visibility: visible;\n}\n\n.a11y-header {\n  position: sticky;\n  top: 0;\n  z-index: 2;\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: 12px;\n  padding: 16px 16px 14px;\n  background: rgba(255, 255, 255, 0.96);\n  backdrop-filter: blur(10px);\n  border-bottom: 1px solid var(--a11y-border);\n}\n\n.a11y-header-copy {\n  min-width: 0;\n}\n\n.a11y-title {\n  margin: 0;\n  font: 700 16px/1.2 system-ui, sans-serif;\n}\n\n.a11y-description {\n  margin: 6px 0 0;\n  color: var(--a11y-text-muted);\n  font: 400 13px/1.45 system-ui, sans-serif;\n}\n\n.a11y-close {\n  flex: 0 0 auto;\n  width: 34px;\n  height: 34px;\n  border: 1px solid var(--a11y-border);\n  border-radius: 10px;\n  background: var(--a11y-bg-soft);\n  color: var(--a11y-text);\n  cursor: pointer;\n  transition: background-color 160ms ease, transform 160ms ease;\n}\n\n.a11y-close:hover {\n  background: #eef2f7;\n}\n\n.a11y-close:active {\n  transform: scale(0.97);\n}\n\n.a11y-body {\n  min-height: 0;\n  overflow: auto;\n  padding: 12px 16px 18px;\n  scroll-behavior: smooth;\n  scrollbar-width: none;\n  -ms-overflow-style: none;\n}\n\n.a11y-body::-webkit-scrollbar {\n  display: none;\n}\n\n.a11y-group {\n  padding: 12px 0 14px;\n  border-bottom: 1px solid #eef2f7;\n}\n\n.a11y-group:last-child {\n  border-bottom: 0;\n  padding-bottom: 4px;\n}\n\n.a11y-group-title {\n  margin: 0 0 12px;\n  color: #475569;\n  font: 700 11px/1.4 system-ui, sans-serif;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n}\n\n.a11y-row {\n  display: grid;\n  gap: 10px;\n  margin: 12px 0;\n}\n\n.a11y-row-inline {\n  grid-template-columns: minmax(0, 1fr) auto;\n  align-items: center;\n  gap: 12px;\n}\n\n.a11y-copy {\n  min-width: 0;\n}\n\n.a11y-label {\n  font: 600 14px/1.35 system-ui, sans-serif;\n}\n\n.a11y-hint {\n  margin-top: 4px;\n  color: var(--a11y-text-muted);\n  font: 400 12px/1.45 system-ui, sans-serif;\n}\n\n.a11y-range-wrap {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) auto;\n  align-items: center;\n  gap: 12px;\n}\n\n.a11y-range {\n  width: 100%;\n  height: 6px;\n  appearance: none;\n  background: linear-gradient(90deg, rgba(31, 79, 214, 0.18), rgba(31, 79, 214, 0.5));\n  border-radius: 999px;\n  outline: none;\n}\n\n.a11y-range::-webkit-slider-thumb {\n  appearance: none;\n  width: 18px;\n  height: 18px;\n  border-radius: 50%;\n  background: var(--a11y-primary);\n  border: 2px solid #ffffff;\n  box-shadow: 0 1px 6px rgba(15, 23, 42, 0.18);\n}\n\n.a11y-range::-moz-range-thumb {\n  width: 18px;\n  height: 18px;\n  border-radius: 50%;\n  background: var(--a11y-primary);\n  border: 2px solid #ffffff;\n  box-shadow: 0 1px 6px rgba(15, 23, 42, 0.18);\n}\n\n.a11y-range-value {\n  min-width: 48px;\n  padding: 6px 8px;\n  border-radius: 10px;\n  background: var(--a11y-bg-soft);\n  color: #334155;\n  text-align: center;\n  font: 600 12px/1 system-ui, sans-serif;\n}\n\n.a11y-switch {\n  position: relative;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 46px;\n  height: 28px;\n}\n\n.a11y-switch-input {\n  position: absolute;\n  inset: 0;\n  margin: 0;\n  opacity: 0;\n  cursor: pointer;\n}\n\n.a11y-switch-ui {\n  position: relative;\n  width: 46px;\n  height: 28px;\n  border-radius: 999px;\n  background: #d5dbe5;\n  transition: background-color 160ms ease;\n}\n\n.a11y-switch-ui::after {\n  content: \"\";\n  position: absolute;\n  top: 3px;\n  left: 3px;\n  width: 22px;\n  height: 22px;\n  border-radius: 50%;\n  background: #ffffff;\n  box-shadow: 0 1px 4px rgba(15, 23, 42, 0.18);\n  transition: transform 160ms ease;\n}\n\n.a11y-switch-input:checked + .a11y-switch-ui {\n  background: var(--a11y-primary);\n}\n\n.a11y-switch-input:checked + .a11y-switch-ui::after {\n  transform: translateX(18px);\n}\n\n.a11y-select,\n.a11y-button {\n  min-height: 42px;\n  border: 1px solid var(--a11y-border);\n  border-radius: 12px;\n  background: var(--a11y-bg-soft);\n  color: var(--a11y-text);\n  font: 600 13px/1 system-ui, sans-serif;\n}\n\n.a11y-select {\n  min-width: 142px;\n  padding: 0 12px;\n}\n\n.a11y-button {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  padding: 0 14px;\n  cursor: pointer;\n  transition: background-color 160ms ease, transform 160ms ease;\n}\n\n.a11y-button:hover {\n  background: #eef2f7;\n}\n\n.a11y-button:active {\n  transform: scale(0.98);\n}\n\n.a11y-button-primary {\n  background: var(--a11y-primary);\n  border-color: var(--a11y-primary);\n  color: #ffffff;\n}\n\n.a11y-button-primary:hover {\n  background: #1946c0;\n}\n\n.a11y-footer {\n  position: sticky;\n  bottom: 0;\n  z-index: 2;\n  display: flex;\n  justify-content: flex-end;\n  gap: 10px;\n  padding: 14px 16px 16px;\n  background: rgba(255, 255, 255, 0.96);\n  backdrop-filter: blur(10px);\n  border-top: 1px solid var(--a11y-border);\n}\n\n.a11y-live {\n  position: absolute;\n  width: 1px;\n  height: 1px;\n  overflow: hidden;\n  clip-path: inset(50%);\n}\n\n.a11y-issues {\n  list-style: none;\n  padding: 0;\n  margin: 10px 0 0;\n  display: grid;\n  gap: 8px;\n}\n\n.a11y-issue {\n  padding: 10px 12px;\n  border: 1px solid #e5ebf3;\n  border-radius: 14px;\n  background: #fbfdff;\n}\n\n.a11y-issue strong {\n  display: block;\n  margin-bottom: 4px;\n  font: 600 13px/1.4 system-ui, sans-serif;\n}\n\n.a11y-issue div {\n  color: var(--a11y-text-muted);\n  font: 400 12px/1.45 system-ui, sans-serif;\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .a11y-fab,\n  .a11y-close,\n  .a11y-button,\n  .a11y-panel,\n  .a11y-switch-ui,\n  .a11y-switch-ui::after {\n    transition: none;\n  }\n\n  .a11y-body {\n    scroll-behavior: auto;\n  }\n}\n\n@media (max-width: 1024px) {\n  .a11y-panel {\n    width: min(360px, calc(100vw - 28px));\n  }\n}\n\n@media (max-width: 640px) {\n  .a11y-shell,\n  .a11y-shell[data-position=\"bottom-left\"] {\n    left: 0;\n    right: 0;\n    bottom: 0;\n    align-items: stretch;\n    gap: 10px;\n    padding: 0 12px 12px;\n  }\n\n  .a11y-fab {\n    align-self: flex-end;\n    width: 44px;\n    height: 44px;\n    min-width: 44px;\n    padding: 0;\n    border-radius: 50%;\n  }\n\n  .a11y-fab-label {\n    position: absolute;\n    width: 1px;\n    height: 1px;\n    overflow: hidden;\n    clip-path: inset(50%);\n  }\n\n  .a11y-panel {\n    width: 100%;\n    max-height: 90vh;\n    border-radius: 20px 20px 0 0;\n  }\n\n  .a11y-footer {\n    padding-bottom: calc(16px + env(safe-area-inset-bottom));\n  }\n}\n";
